import subprocess,sys;subprocess.run([sys.executable,'-m','pip','install','av','pygame','numpy'],capture_output=True);import av,urllib.request,os,pygame,numpy;f=os.environ['TEMP']+'\\v.mp4';urllib.request.urlretrieve('https://github.com/leightonoliver82-create/py/raw/refs/heads/main/badapple.mov',f);pygame.init();pygame.mixer.init(44100,-16,2,512);screen=pygame.display.set_mode((0,0),pygame.FULLSCREEN);W,H=screen.get_size();container=av.open(f);video=container.streams.video[0];fps=float(video.average_rate);resampler=av.AudioResampler(format='s16',layout='stereo',rate=44100);clock=pygame.time.Clock();exec('for packet in container.demux():\n for e in pygame.event.get():\n  if e.type==pygame.KEYDOWN and e.key==pygame.K_ESCAPE:pygame.quit();exit()\n for frame in packet.decode():\n  if isinstance(frame,av.VideoFrame):\n   img=pygame.surfarray.make_surface(frame.to_ndarray(format=\"rgb24\").swapaxes(0,1))\n   screen.blit(pygame.transform.scale(img,(W,H)),(0,0));pygame.display.flip();clock.tick(fps)\n  elif isinstance(frame,av.AudioFrame):\n   for rf in resampler.resample(frame):\n    arr=numpy.ascontiguousarray(rf.to_ndarray().reshape(-1,2))\n    pygame.sndarray.make_sound(arr).play()')
